import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbCodeBlockImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-code-block-basic',
  imports: [HbCodeBlockImports],
  template: `
    <hb-code-block
      class="w-full max-w-2xl"
      hbLanguage="typescript"
      hbFilename="classes.ts"
      [hbCode]="code"
    />
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoCodeBlockBasicComponent {
  protected readonly code =
    "import { cn } from '@herbst/ui';\n" +
    '\n' +
    "export const classes = cn('px-4 py-2', active && 'bg-primary');";
}

import { ChangeDetectionStrategy, Component } from '@angular/core';

import { HbCodeBlockImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-code-block-languages',
  imports: [HbCodeBlockImports],
  template: `
    <div class="flex w-full max-w-2xl flex-col gap-3">
      <hb-code-block hbLanguage="bash" hbFilename="terminal" [hbCode]="bash" />
      <hb-code-block hbLanguage="css" hbFilename="theme.css" [hbCode]="css" />
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoCodeBlockLanguagesComponent {
  protected readonly bash = 'npx herbst-ui@latest add button card';

  protected readonly css =
    ':root {\n' +
    '  --primary: oklch(0.545 0.155 42);\n' +
    '  --background: oklch(0.973 0.005 95);\n' +
    '}';
}

import { ChangeDetectionStrategy, Component, signal } from '@angular/core';

import { HbCodeBlockImports } from '@herbst/ui';

@Component({
  selector: 'hb-demo-code-block-options',
  imports: [HbCodeBlockImports],
  template: `
    <div class="flex w-full max-w-2xl flex-col gap-2">
      <hb-code-block
        hbLanguage="json"
        [hbShowHeader]="false"
        hbWrap
        [hbMaxHeight]="140"
        [hbCode]="code"
        (hbCopy)="copied.set(true)"
      />

      <p class="font-mono text-[12px] text-muted-foreground">
        {{
          copied()
            ? 'Copied to clipboard'
            : 'No header · hover to copy · wraps · scrolls past 140px'
        }}
      </p>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class HbDemoCodeBlockOptionsComponent {
  protected readonly copied = signal(false);

  protected readonly code =
    '{\n' +
    '  "title": "Autumn in the Black Forest",\n' +
    '  "city": "Freiburg",\n' +
    '  "tree": "Oak",\n' +
    '  "taken": "2026-11-03",\n' +
    '  "notes": "Leaves turning amber and rust; a cool wind off the hills; mist settling over the valley below."\n' +
    '}';
}
